COVER_URLS = [
    "https://covers.openlibrary.org/b/id/10909258-L.jpg",
    "https://covers.openlibrary.org/b/id/12645114-L.jpg",
    "https://covers.openlibrary.org/b/id/8231538-L.jpg",
    "https://covers.openlibrary.org/b/id/10527843-L.jpg",
    "https://covers.openlibrary.org/b/id/7984916-L.jpg",
    "https://covers.openlibrary.org/b/id/10494164-L.jpg",
    "https://covers.openlibrary.org/b/id/8739161-L.jpg",
    "https://covers.openlibrary.org/b/id/9255566-L.jpg",
]


class Command(BaseCommand):
    help = "Seed books app with genres, authors, publishers, collections and 40+ books per genre"

    @transaction.atomic
    def handle(self, *args, **options):
        self.stdout.write("🌱  Starting seed...")

        # ── Genres ──────────────────────────────────────────────
        self.stdout.write("  Creating genres...")
        genre_objects = {}
        for name in GENRES:
            obj, created = Genre.objects.get_or_create(name=name)
            genre_objects[name] = obj
            if created:
                self.stdout.write(f"    + Genre: {name}")

        # ── Authors ─────────────────────────────────────────────
        self.stdout.write("  Creating authors...")
        author_objects = {}
        for name in AUTHORS:
            obj, created = Author.objects.get_or_create(name=name)
            author_objects[name] = obj

        # ── Publishers ───────────────────────────────────────────
        self.stdout.write("  Creating publishers...")
        publisher_objects = []
        for p in PUBLISHERS:
            obj, created = Publisher.objects.get_or_create(
                name=p["name"],
                defaults={"description": p["description"], "logo": p["logo"]},
            )
            publisher_objects.append(obj)

        # ── Collections ──────────────────────────────────────────
        self.stdout.write("  Creating collections...")
        collection_objects = []
        for name in COLLECTIONS:
            obj, created = Collection.objects.get_or_create(name=name)
            collection_objects.append(obj)

        # ── Books ────────────────────────────────────────────────
        self.stdout.write("  Creating books...")
        total = 0
        for genre_name, books in BOOKS_BY_GENRE.items():
            genre = genre_objects[genre_name]
            for (
                title, description, price, pages,
                cover_type, language, isbn, quantity,
                discount_price, author_name,
            ) in books:
                # Skip if already exists (idempotent)
                if Book.objects.filter(isbn=isbn).exists():
                    continue

                publisher = random.choice(publisher_objects)
                cover = random.choice(COVER_URLS)

                book = Book.objects.create(
                    title=title,
                    description=description,
                    price=price,
                    pages=pages,
                    cover_type=cover_type,
                    language=language,
                    isbn=isbn,
                    quantity=quantity,
                    discount_price=discount_price,
                    publisher=publisher,
                    cover=cover,
                )

                # M2M: BookGenre
                BookGenre.objects.get_or_create(book=book, genre=genre)

                # M2M: BookAuthor
                author = author_objects.get(author_name)
                if author:
                    BookAuthor.objects.get_or_create(book=book, author=author)

                # M2M: BookCollection (randomly assign 0-2 collections)
                for coll in random.sample(collection_objects, k=random.randint(0, 2)):
                    BookCollection.objects.get_or_create(book=book, collection=coll)

                total += 1

        self.stdout.write(
            self.style.SUCCESS(
                f"\n✅  Done! Created {total} new books across {len(GENRES)} genres."
            )
        )
